program Ar6(input, output);{input: N numbers, stored in array X.
                            output: array X's cells organized in araay Y so first stored
                            the complete numbers that biegger than 100}
uses crt;
const
N=10;
Type
Ar= Array [1..N] of real;
Var
X: Ar;
Y: Ar;
i: integer;
j: integer;
begin
     clrscr;
     writeln('PLEASE ENTER ',N,' NUMBERS:');
     j:=1;
     for i:=1 to N do
           begin
                readln(X[i]);
                if {(X[i]/1<>X[i]) and }(X[i]>100) then {if the number>100 and complete store it in array Y's first cells}
                   begin
                        Y[j]:=X[i];
                        j:=j+1;
                   end;
           end;
     for i:=1 to N do
         begin
              if {((X[i]/1)<>0) or }(X[i]<=100) then {if the number<100  or incomplete store it in array Y's remaining cells}
                begin
                     Y[j]:=X[i];
                     j:=j+1;
                end;
         end;
     for i:=1 to N do
         write(X[i]:0:1,'  ');
     writeln();
     for i:=1 to N do
         write(Y[i]:0:1,'  ');
     readkey;
end.

program Ar6(input, output);{input: how many people in evey sadna.
                            output: the popular sadna number, the number of
                            people in the less popular sadna an the avarage
                            people for sandna}
uses crt;
const
S=10; {number of Sadnaot}
W=800; {number of Workers}
Type
Ar= Array [1..S] of integer;
Var
Sadna: Ar;
i: integer;
j: integer;
max: integer;
maxi: integer;
min: integer;
begin
     clrscr;
     randomize;
     max:=0;
     min:=800;
     for i:=1 to S do
         Sadna[i]:=0;
     for i:=1 to W do {for every worker, get the sadna}
           begin
                j:=random(10)+1;
                Sadna[j]:=Sadna[j]+1;
           end;
     writeln('Sadna number,     people in sadna');
     for i:=1 to S do
         begin
              write(i,'                  ');
              writeln(Sadna[i]);
              if Sadna[i]>=max then {get the max number of people in one sadna}
                 begin
                      max:=Sadna[i];
                      maxi:=i;
                 end;
              if Sadna[i]<min then {get the min number of people in one sadna}
                 min:=Sadna[i];
         end;
     writeln();
     writeln('The popular sadna is sadna number ', maxi);
     writeln('The number of people in the less popular sadna is ', min);
     writeln('The avarge people for sadna is ', W/S:0:2);
     readkey;
end.
